# websockify bridging 6080 -> VNC 5901
nohup websockify 127.0.0.1:6080 127.0.0.1:5901 >/var/log/websockify.log 2>&1 &
sleep 1
ln -sf /usr/share/novnc/vnc.html /usr/share/novnc/index.html
cat > /etc/nginx/sites-available/default <<'EOF'
server {
    listen 80 default_server;
    listen [::]:80 default_server;
    root /usr/share/novnc;
    index index.html vnc.html;

    location / {
        try_files $uri $uri/ =404;
    }

    location /websockify {
        proxy_http_version 1.1;
        proxy_pass http://127.0.0.1:6080;
        proxy_set_header Upgrade $http_upgrade;
        proxy_set_header Connection "upgrade";
        proxy_set_header Host $host;
        proxy_read_timeout 61s;
        proxy_buffering off;
    }
}
EOF
nginx -t 2>&1 | tail -2
nginx 2>&1 | tail -2 || service nginx start 2>&1 | tail -2
sleep 1
ss -ltnp | grep -E ':80 |:6080'
echo "HTTP:"; curl -s -o /dev/null -w "%{http_code}\n" http://127.0.0.1/vnc.html

